WebLink.url:
popitup('/apex/TrusteeAssignment?Id={!Insolvency__c.Id}', 'Assign Trustee')

function popitup(url,windowName) {
       newwindow=window.open(url,windowName,'height=500,width=1100,top=200,left=100,scrollbars=yes, resizable=yes');
       if (window.focus) {newwindow.focus()}
       return false;
     }
